{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを2026年5月13日をもちまして正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例を毎週水曜日10:00から1時間枠で開催し、各部署から1名ずつ出席必須とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "開発ベンダーの選定において「コマツバ・ソリューションズ」を候補として残し、技術面およびテスト体制の確認のために相手先との対話の場を設ける。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "共通基盤（認証・マスタ配信）の方針として、サクラ商事社への共同利用（第3案）で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "移行方式として、拠点をグループに分け段階的に切り替える方式（B案）を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "本番リリース目標日を当初の「9月末」から「10月15日」へ延期・変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "システム切り替え作業は、平日の夜間ではなく土曜日の深夜帯にて行う方針で進める。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D8",
      "content": "新システムへの移行にあたり既存のロール定義を流用し、新規設計は行わない。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "システムの一次受け窓口を情報システム部から品質保証部（QA）へ変更する。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
