      "due": "2026-06-01"
    },
    {
      "id": "A7",
      "task": "既存テストケースの棚卸しを行い、一覧表（有効/捨てる/修正必要）を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-29"
    },
    {
      "id": "A8",
